#include<bits/stdc++.h>
#define int long long
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI N=1e6+10;
int n,k;
int c[N];
int f[N];
int d[N][25],_d[N][25];
vector<int>t[N];
int qp(int a,int b)
{
	int s=1;
	wh(b)
	{
		if(b&1)s=s*a;
		a=a*a;
		b>>=1;
	}
	return s;
}
void dfs(int x)
{
	FOR(j,0,k)
	{
		d[x][j]=c[x];
	}
	FOR(i,0,t[x].size()-1)
	{
		int to=t[x][i];
		if(to!=f[x])
		{
			f[to]=x;
			dfs(to);
			FOR(j,1,k)
			{
				d[x][j]+=d[to][j-1];
			}
		}
	}
}
void d2(int x)
{
	FOR(i,0,t[x].size()-1)
	{
		int to=t[x][i];
		if(to!=f[x])
		{
			_d[to][1]=c[x];
			FOR(j,2,k)
			{
				_d[to][j]=d[x][j-1]-d[to][j-2]+_d[x][j-1];
			}
			d2(to);
		}
	}
}
signed main()
{
	IOS
    cin>>n>>k;
	FOR(i,1,n)
	{
		t[i].clear();
		f[i]=0;
	}
	FOR(i,1,n-1)
	{
		int u,v;
		cin>>u>>v;
		t[u].pb(v);
		t[v].pb(u);
	}
	FOR(i,1,n)
	{
		cin>>c[i];
	}
    if(n==1)
    {
        cout<<c[1];//特判
        return false;
    }
	dfs(1);//DP
	d2(1);
	FOR(i,1,n)
	{
		cout<<d[i][k]+_d[i][k]<<'\n';
	}
	return false;
}
